// ═══════════════════════════════════════════
//  ENHANCED MARKDOWN RENDERER (with Mermaid)
// ═══════════════════════════════════════════
const MarkdownRenderer = ({ text, onHeadingsExtracted, themeName }) => {
  const headingsRef = useRef([]);
  const mermaidContainers = useRef({});
  const [lightbox, setLightbox] = useState(null); // {src, alt}

  // Close lightbox on Escape — capture phase so the reader's own Escape
  // handler (which closes the whole modal) doesn't also fire
  useEffect(() => {
    if (!lightbox) return;
    const onKey = (e) => {
      if (e.key === "Escape") {
        e.stopPropagation();
        setLightbox(null);
      }
    };
    window.addEventListener("keydown", onKey, true);
    return () => window.removeEventListener("keydown", onKey, true);
  }, [lightbox]);
  // Counter, not boolean: bumping it forces diagrams to re-render after a
  // theme change re-initializes mermaid with the matching palette.
  const [mermaidReady, setMermaidReady] = useState(0);

  // Initialize mermaid (re-runs when the site theme flips)
  useEffect(() => {
    const initMermaid = async () => {
      try {
        const mermaidModule = await import("mermaid");
        const mermaid = mermaidModule.default;
        const isLight =
          themeName === "light" || document.querySelector(".light-mode");
        mermaid.initialize({
          startOnLoad: false,
          theme: isLight ? "default" : "dark",
          securityLevel: "loose",
          fontFamily: "inherit",
          themeVariables: isLight
            ? { primaryColor: "#ede9fe", primaryBorderColor: "#8b5cf6" }
            : {
                primaryColor: "#2e1065",
                primaryBorderColor: "#8b5cf6",
                primaryTextColor: "#e9e4f8",
                lineColor: "#7c6fa8",
              },
          flowchart: { curve: "basis", padding: 14, useMaxWidth: true },
        });
        setMermaidReady((n) => n + 1);
      } catch (err) {
        console.warn("Mermaid not available:", err.message);
      }
    };
    initMermaid();
  }, [themeName]);

  // Extract headings for TOC
  useEffect(() => {
    if (!text) return;
    const lines = text.split("\n");
    const headings = [];
    lines.forEach((line, idx) => {
      const match = line.match(/^(#{1,3})\s+(.+)$/);
      if (match) {
        headings.push({
          level: match[1].length,
          text: match[2].replace(/\*\*/g, "").replace(/`/g, ""),
          // Text-only id — must produce the same value as renderLine's
          // heading id so TOC clicks and active-highlight can find the node
          id: `heading-${match[2]
            .replace(/[^a-zA-Z0-9]/g, "-")
            .toLowerCase()}`,
        });
      }
    });
    headingsRef.current = headings;
    if (onHeadingsExtracted) onHeadingsExtracted(headings);
  }, [text, onHeadingsExtracted]);

  if (!text) return null;

  const renderLine = (line, key, opts = {}) => {
    let html = line;
    // Bold
    html = html.replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>");
    // Italic
    html = html.replace(/(?<!\*)\*(?!\*)(.*?)(?<!\*)\*(?!\*)/g, "<em>$1</em>");
    // Inline Code
    html = html.replace(/`(.*?)`/g, '<code class="md-inline-code">$1</code>');
    // Links
    html = html.replace(
      /\[([^\]]+)\]\(([^)]+)\)/g,
      '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>'
    );
    // Strikethrough
    html = html.replace(/~~(.*?)~~/g, "<del>$1</del>");

    // Images (click to open lightbox)
    const imgMatch = line.match(/^!\[([^\]]*)\]\(([^)]+)\)$/);
    if (imgMatch) {
      return (
        <figure key={key} className="md-figure">
          <img
            src={imgMatch[2]}
            alt={imgMatch[1]}
            className="md-image md-image-zoomable"
            loading="lazy"
            onClick={() => setLightbox({ src: imgMatch[2], alt: imgMatch[1] })}
          />
          {imgMatch[1] && (
            <figcaption className="md-figcaption">{imgMatch[1]}</figcaption>
          )}
        </figure>
      );
    }

    // Big stat highlight: [[stat: 88% | of my RAG latency was retrieval]]
    const statMatch = line
      .trim()
      .match(/^\[\[stat:\s*([^|\]]+)\|([^\]]+)\]\]$/);
    if (statMatch) {
      return (
        <div key={key} className="md-stat">
          <span className="md-stat-number">{statMatch[1].trim()}</span>
          <span className="md-stat-caption">{statMatch[2].trim()}</span>
        </div>
      );
    }

    // Image credit line (italic with "Photo by")
    if (line.startsWith("*Photo by") || line.startsWith("*Image")) {
      return (
        <p
          key={key}
          className="md-image-credit"
          dangerouslySetInnerHTML={{
            __html: html.replace(/^\*/, "").replace(/\*$/, ""),
          }}
        />
      );
    }

    // Headings
    const headingMatch = line.match(/^(#{1,3})\s+(.+)$/);
    if (headingMatch) {
      const level = headingMatch[1].length;
      const content = html.replace(/^#{1,3}\s+/, "");
      const id = `heading-${headingMatch[2]
        .replace(/[^a-zA-Z0-9]/g, "-")
        .toLowerCase()}`;
      const Tag = `h${level}`;
      return (
        <Tag key={key} id={id} dangerouslySetInnerHTML={{ __html: content }} />
      );
    }

    // Horizontal rule
    if (/^(-{3,}|\*{3,}|_{3,})$/.test(line.trim())) {
      return <hr key={key} className="md-hr" />;
    }

    // Table rows
    if (line.startsWith("|") && line.endsWith("|")) {
      const cells = line
        .split("|")
        .filter(Boolean)
        .map((c) => c.trim());
      // Check if separator row
      if (cells.every((c) => /^[-:]+$/.test(c))) {
        return null; // skip separator
      }
      const isHeader = !!opts.tableHeader;
      return (
        <tr key={key}>
          {cells.map((cell, ci) => {
            const CellTag = isHeader ? "th" : "td";
            return (
              <CellTag
                key={ci}
                dangerouslySetInnerHTML={{
                  __html: cell.replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>"),
                }}
              />
            );
          })}
        </tr>
      );
    }

    // Unordered list
    if (/^\s*[-*+]\s/.test(line)) {
      const content = html.replace(/^\s*[-*+]\s/, "");
      return <li key={key} dangerouslySetInnerHTML={{ __html: content }} />;
    }

    // Ordered list
    if (/^\s*\d+\.\s/.test(line)) {
      const content = html.replace(/^\s*\d+\.\s/, "");
      return (
        <li
          key={key}
          className="md-ol-item"
          dangerouslySetInnerHTML={{ __html: content }}
        />
      );
    }

    // Blockquote — emoji-keyed ones become styled callout cards
    if (line.startsWith("> ")) {
      const content = html.substring(2);
      const calloutMatch = content.match(/^(💡|🔥|⚠️|🚨|📌|✅)\s*(.*)$/);
      if (calloutMatch && calloutMatch[2]) {
        const kindMap = {
          "💡": "insight",
          "🔥": "insight",
          "⚠️": "warning",
          "🚨": "warning",
          "📌": "note",
          "✅": "takeaway",
        };
        const labels = {
          insight: "Insight",
          warning: "Watch out",
          note: "Note",
          takeaway: "Takeaway",
        };
        const kind = kindMap[calloutMatch[1]];
        return (
          <div key={key} className={`md-callout md-callout-${kind}`}>
            <span className="md-callout-icon">{calloutMatch[1]}</span>
            <div className="md-callout-body">
              <span className="md-callout-label">{labels[kind]}</span>
              <span
                dangerouslySetInnerHTML={{ __html: calloutMatch[2] }}
              />
            </div>
          </div>
        );
      }
      return (
        <blockquote key={key} dangerouslySetInnerHTML={{ __html: content }} />
      );
    }

    // Empty line
    if (line.trim() === "") return <div key={key} className="md-spacer" />;

    // Regular paragraph
    return <p key={key} dangerouslySetInnerHTML={{ __html: html }} />;
  };

  // Split content by code blocks (including mermaid)
  const parts = text.split(/(```[\s\S]*?```)/g);

  return (
    <div className="md-rendered">
      {parts.map((part, partIdx) => {
        if (part.startsWith("```")) {
          const innerContent = part.slice(3, -3);
          const firstLine = innerContent.split("\n")[0]?.trim().toLowerCase();
          const codeContent = innerContent.split("\n").slice(1).join("\n");

          // Mermaid diagram
          if (firstLine === "mermaid") {
            return (
              <MermaidDiagram
                key={`mermaid-${partIdx}`}
                code={codeContent}
                mermaidReady={mermaidReady}
              />
            );
          }

          // Regular code block
          const lang = firstLine || "";
          const code = codeContent || firstLine;
          return (
            <div key={`code-${partIdx}`} className="md-code-block">
              {lang && lang !== code && (
                <span className="md-code-lang">{lang}</span>
              )}
              <button
                className="md-code-copy"
                onClick={() => {
                  navigator.clipboard.writeText(code);
                }}
                title="Copy code"
              >
                📋
              </button>
              <pre>
                <code>{code}</code>
              </pre>
            </div>
          );
        }

        // Handle tables — group table rows together
        const lines = part.split("\n");
        const rendered = [];
        let tableRows = [];
        let inTable = false;

        lines.forEach((line, lineIdx) => {
          const isTableRow = line.startsWith("|") && line.endsWith("|");
          const isSeparator =
            isTableRow &&
            line
              .split("|")
              .filter(Boolean)
              .every((c) => /^[\s-:]+$/.test(c));

          if (isTableRow) {
            if (!inTable) inTable = true;
            if (!isSeparator) {
              tableRows.push(
                renderLine(line, `${partIdx}-${lineIdx}`, {
                  tableHeader: tableRows.length === 0,
                })
              );
            }
          } else {
            if (inTable && tableRows.length > 0) {
              rendered.push(
                <div
                  key={`table-wrap-${partIdx}-${lineIdx}`}
                  className="md-table-wrapper"
                >
                  <table className="md-table">
                    <thead>{tableRows[0]}</thead>
                    <tbody>{tableRows.slice(1)}</tbody>
                  </table>
                </div>
              );
              tableRows = [];
              inTable = false;
            }
            rendered.push(renderLine(line, `${partIdx}-${lineIdx}`));
          }
        });

        // Flush remaining table
        if (tableRows.length > 0) {
          rendered.push(
            <div key={`table-wrap-${partIdx}-end`} className="md-table-wrapper">
              <table className="md-table">
                <thead>{tableRows[0]}</thead>
                <tbody>{tableRows.slice(1)}</tbody>
              </table>
            </div>
          );
        }

        return rendered;
      })}

      {/* Image lightbox */}
      {lightbox && (
        <div className="md-lightbox" onClick={() => setLightbox(null)}>
          <img src={lightbox.src} alt={lightbox.alt} />
          {lightbox.alt && (
            <span className="md-lightbox-caption">{lightbox.alt}</span>
          )}
          <button
            className="md-lightbox-close"
            onClick={() => setLightbox(null)}
          >
            ✕
          </button>
        </div>
      )}
    </div>
  );
};

// ═══════════════════════════════════════════
//  MERMAID DIAGRAM COMPONENT
// ═══════════════════════════════════════════

// Repair the mermaid mistakes LLMs make most often, so older posts render
// too: typographic quotes/dashes, <br> tags, markdown bold, and unquoted
// node labels containing characters the parser chokes on ( ) / : ,
const sanitizeMermaid = (raw) => {
  let code = (raw || "")
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/[—–]/g, "-")
    .replace(/<br\s*\/?>/gi, " ")
    .replace(/\*\*/g, "");
  // graph TD → flowchart TD (same grammar, newer parser path)
  code = code.replace(/^\s*graph\s+(TD|TB|LR|RL|BT)/m, "flowchart $1");
  // Quote [ ... ] labels with breaking chars — but leave alone labels that
  // are already quoted or that start a shape token like [( or [[
  code = code.replace(
    /\[(?![[("])([^\]"\n]*[()/:,][^\]"\n]*)\]/g,
    (m, label) => `["${label.trim()}"]`
  );
  // Same for { ... } diamond labels (e.g. {Neural Engine (ANE)})
  code = code.replace(
    /\{(?![{"])([^}"\n]*[()/:,][^}"\n]*)\}/g,
    (m, label) => `{"${label.trim()}"}`
  );
  return code.trim();
};

const MermaidDiagram = ({ code, mermaidReady }) => {
  const containerRef = useRef(null);
  const [svgHtml, setSvgHtml] = useState("");
  const [error, setError] = useState(null);
  const [expanded, setExpanded] = useState(false);

  useEffect(() => {
    if (!mermaidReady || !code) return;

    const renderDiagram = async () => {
      const mermaidModule = await import("mermaid");
      const mermaid = mermaidModule.default;
      const attempt = async (source) => {
        const id = `mermaid-blog-${Date.now()}-${Math.random()
          .toString(36)
          .substr(2, 5)}`;
        try {
          const { svg } = await mermaid.render(id, source);
          return svg;
        } catch (err) {
          // mermaid can leave an orphan error node in <body> on failure
          document.getElementById(id)?.remove();
          document.getElementById(`d${id}`)?.remove();
          throw err;
        }
      };

      try {
        const svg = await attempt(sanitizeMermaid(code));
        setSvgHtml(svg);
        setError(null);
      } catch (firstErr) {
        try {
          // Fall back to the raw source in case sanitizing broke something
          const svg = await attempt(code.trim());
          setSvgHtml(svg);
          setError(null);
        } catch (err) {
          console.warn("Mermaid render failed:", err.message);
          setError(err.message);
        }
      }
    };

    renderDiagram();
  }, [code, mermaidReady]);

  if (error) {
    // Quiet failure: readers see a small collapsed note, not broken output
    return (
      <details className="mermaid-fallback">
        <summary>📐 Diagram unavailable — view source</summary>
        <pre>
          <code>{code}</code>
        </pre>
      </details>
    );
  }

  return (
    <div className={`mermaid-blog-diagram ${expanded ? "expanded" : ""}`}>
      <div className="mermaid-diagram-header">
        <span>📐 Diagram</span>
        <div className="mermaid-diagram-actions">
          <button
            onClick={() => setExpanded(!expanded)}
            title={expanded ? "Collapse" : "Expand"}
          >
            {expanded ? "🔽" : "🔼"}
          </button>
          <button
            onClick={() => {
              navigator.clipboard.writeText(code);
            }}
            title="Copy Mermaid code"
          >
            📋
          </button>
        </div>
      </div>
      <div className="mermaid-diagram-body" ref={containerRef}>
        {svgHtml ? (
          <div dangerouslySetInnerHTML={{ __html: svgHtml }} />
        ) : (
          <div className="mermaid-loading">
            <span className="gen-spinner" /> Rendering diagram...
          </div>
        )}
      </div>
    </div>
  );
};

const publishToExternalPlatforms = async (
  blogData,
  platforms = ["devto", "hashnode"]
) => {
  try {
    const response = await fetch(`${FIREBASE_FUNCTIONS_URL}/publishBlog`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        title: blogData.title,
        // External platforms don't know our [[stat:]] card syntax — flatten
        // it to a bold blockquote so it still reads well on Dev.to/Hashnode
        content: (blogData.content || "").replace(
          /^\[\[stat:\s*([^|\]]+)\|([^\]]+)\]\]$/gm,
          "> **$1** $2"
        ),
        tags: blogData.tags || [],
        slug: blogData.slug || "",
        excerpt: blogData.excerpt || "",
        platforms: platforms,
        coverImageURL: blogData.coverImageURL || null, // ← ADD THIS
      }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error || `HTTP ${response.status}`);
    }

    return await response.json();
  } catch (err) {
    console.error("External publish error:", err);
    throw err;
  }
};
